"use client";

import { useRef } from "react";

/**
 * Landing page.
 *
 * The hero background is a real ForgeVid render (public/videos/hero.mp4) — the
 * product demonstrating itself. Same for every tile in the Examples strip: each
 * was generated by this platform from a one-line prompt, not sourced elsewhere.
 *
 * The video is decorative: it is muted, aria-hidden, carries a poster frame so
 * the first paint is never blank, and is hidden entirely under
 * prefers-reduced-motion (the poster shows instead).
 */

interface Example {
  slug: string;
  label: string;
  prompt: string;
  aspect: "16:9" | "9:16" | "1:1";
}

const EXAMPLES: Example[] = [
  {
    slug: "product",
    label: "Product ad",
    prompt: "Sleek marketing spot for wireless earbuds",
    aspect: "16:9",
  },
  {
    slug: "social",
    label: "Social reel",
    prompt: "A chef plating a colorful bowl of fresh food",
    aspect: "9:16",
  },
  {
    slug: "travel",
    label: "Travel reel",
    prompt: "Sunrise beaches, mountain ridges, lantern-lit streets",
    aspect: "1:1",
  },
  {
    slug: "realestate",
    label: "Property tour",
    prompt: "A modern home: living room, kitchen, garden at golden hour",
    aspect: "16:9",
  },
];

const STEPS = [
  {
    n: "01",
    title: "Describe it, or paste a URL",
    body: "Type what you want, or drop in a product page — ForgeVid reads it and writes a script grounded in what the page actually says.",
  },
  {
    n: "02",
    title: "It finds the footage and the voice",
    body: "Scenes are matched to real stock footage or your own uploads, narrated by an AI voice or your own recording, and cut to the speech.",
  },
  {
    n: "03",
    title: "Edit any scene, re-render in seconds",
    body: "Swap a clip, choose a specific image, retime a beat, or just say “make scene 2 faster”. Re-renders reuse cached narration.",
  },
];

/**
 * Every tile gets the SAME media height so the grid rows line up; the clip is
 * letter/pillar-boxed inside it (object-contain on black) rather than cropped.
 * Cropping a 9:16 reel into a 16:9 box — or the reverse — would hide exactly
 * the thing this section exists to show: that ForgeVid renders all three shapes.
 */
const MEDIA_BOX = "relative h-64 w-full overflow-hidden bg-black";

function ExampleTile({ example }: { example: Example }) {
  const videoRef = useRef<HTMLVideoElement>(null);

  // Play only while the user is looking at it: four autoplaying videos would
  // cost several megabytes and a lot of battery for no benefit.
  const play = () => {
    const video = videoRef.current;
    if (!video) return;
    video.play().catch(() => {
      /* autoplay policy — the poster stays up, which is fine */
    });
  };
  const stop = () => {
    const video = videoRef.current;
    if (!video) return;
    video.pause();
    video.currentTime = 0;
  };

  return (
    <figure
      className="glass-card group flex h-full flex-col overflow-hidden rounded-2xl hover-lift"
      onMouseEnter={play}
      onMouseLeave={stop}
      onFocus={play}
      onBlur={stop}
      tabIndex={0}
    >
      <div className={MEDIA_BOX}>
        {/* WebM first: some browsers (and headless Chromium) ship no H.264. */}
        <video
          ref={videoRef}
          className="absolute inset-0 h-full w-full object-contain"
          poster={`/videos/examples/${example.slug}.jpg`}
          muted
          loop
          playsInline
          preload="none"
        >
          <source src={`/videos/examples/${example.slug}.webm`} type="video/webm" />
          <source src={`/videos/examples/${example.slug}.mp4`} type="video/mp4" />
        </video>
        <span className="absolute right-2 top-2 rounded-md bg-black/60 px-2 py-0.5 text-[11px] font-medium text-gray-200 backdrop-blur">
          {example.aspect}
        </span>
        <span className="pointer-events-none absolute inset-0 flex items-center justify-center transition-opacity group-hover:opacity-0">
          <span className="flex h-12 w-12 items-center justify-center rounded-full bg-white/15 backdrop-blur">
            <svg className="ml-0.5 h-5 w-5 text-white" fill="currentColor" viewBox="0 0 24 24">
              <path d="M8 5v14l11-7z" />
            </svg>
          </span>
        </span>
      </div>
      <figcaption className="flex flex-1 flex-col p-4">
        <p className="text-sm font-semibold text-white">{example.label}</p>
        <p className="mt-1 text-xs leading-relaxed text-gray-400">“{example.prompt}”</p>
      </figcaption>
    </figure>
  );
}

